const safeString = (value) => {
  if (value === undefined || value === null) {
    return '';
  }
  return String(value).trim();
};

const truncate = (value, maxLength = 500) => {
  const text = safeString(value).replace(/\s+/g, ' ');
  if (text.length <= maxLength) {
    return text;
  }
  return text.slice(0, Math.max(0, maxLength - 3)) + '...';
};

const sanitizeLarkMd = (value) => truncate(value, 1200)
  .replace(/<at\b/gi, '&lt;at')
  .replace(/<\/at>/gi, '&lt;/at&gt;')
  .replace(/([*_~])/g, '\\$1');

const toIntText = (value) => {
  const numericValue = Number(value);
  return Number.isFinite(numericValue) ? String(Math.round(numericValue)) : '-';
};

const isHttpUrl = (value) => /^https?:\/\//i.test(safeString(value));

const webhookConfigured = Boolean(safeString($env.FEISHU_WEBHOOK_URL));
const shouldNotify = Boolean($json.should_notify);
const vaultWriteStatus = safeString($json.vault_write_status || $json.vault_write || '');
const notificationMode = safeString($json.notification_mode || 'silent') || 'silent';
const aiScore = $json.ai_score && typeof $json.ai_score === 'object' ? $json.ai_score : {};
const itemId = safeString($json.item_id || $json.id || '');
const sourceName = safeString($json.source_display_name || $json.source_name || $json.author || '');
const sourceType = safeString($json.source_type || $json.media_type || '');
const sourceLine = [sourceType, sourceName].filter(Boolean).join(' / ');
const title = truncate($json.title || 'Untitled', 120);
const summary = truncate($json.summary || $json.note_quick_take || $json.upstream_summary || '', 700);
const reason = truncate($json.reason || $json.note_why_useful || '', 360);
const canonicalUrl = safeString($json.canonical_url || '');
const vaultPath = safeString($json.vault_path || $json.relativeFilePath || '');
const dedupeAction = safeString($json.dedupe_action || '');
const publishedAt = safeString($json.published_at || '');
const keepScore = toIntText(aiScore.keep_score ?? Number($json.score || 0) * 100);
const notifyScore = toIntText(aiScore.notify_score);
const referenceScore = toIntText(aiScore.reference_score);
const actionScore = toIntText(aiScore.action_score);

let skippedReason = '';
if (!webhookConfigured) {
  skippedReason = 'missing_feishu_webhook_url';
} else if (!shouldNotify) {
  skippedReason = 'should_notify_false';
} else if (vaultWriteStatus !== 'written') {
  skippedReason = 'vault_not_written:' + (vaultWriteStatus || 'unknown');
}

const shouldDispatch = !skippedReason;
const scoreLine = 'Keep ' + keepScore + ' / Notify ' + notifyScore + ' / Reference ' + referenceScore + ' / Action ' + actionScore;
const previewLines = [
  '\u3010AI \u4fe1\u606f\u6458\u8981\u3011' + title,
  sourceLine ? '\u6765\u6e90\uff1a' + sourceLine : '',
  publishedAt ? '\u65f6\u95f4\uff1a' + publishedAt : '',
  dedupeAction ? '\u53bb\u91cd\uff1a' + dedupeAction + ' / \u901a\u77e5\uff1a' + notificationMode : '\u901a\u77e5\uff1a' + notificationMode,
  '\u8bc4\u5206\uff1a' + scoreLine,
  summary ? '\u6458\u8981\uff1a' + summary : '',
  reason ? '\u7406\u7531\uff1a' + reason : '',
  vaultPath ? 'Obsidian\uff1a' + vaultPath : '',
  canonicalUrl ? '\u539f\u6587\uff1a' + canonicalUrl : ''
].filter(Boolean);
const messagePreview = previewLines.join('\n');

const mainMarkdown = [
  '**' + sanitizeLarkMd(title) + '**',
  sourceLine ? '**\u6765\u6e90**\uff1a' + sanitizeLarkMd(sourceLine) : '',
  publishedAt ? '**\u65f6\u95f4**\uff1a' + sanitizeLarkMd(publishedAt) : '',
  '**\u8bc4\u5206**\uff1a' + sanitizeLarkMd(scoreLine),
  dedupeAction ? '**\u53bb\u91cd / \u901a\u77e5**\uff1a' + sanitizeLarkMd(dedupeAction + ' / ' + notificationMode) : '**\u901a\u77e5**\uff1a' + sanitizeLarkMd(notificationMode),
  summary ? '**\u6458\u8981**\n' + sanitizeLarkMd(summary) : '',
  reason ? '**\u7406\u7531**\n' + sanitizeLarkMd(reason) : '',
  vaultPath ? '**Obsidian**\uff1a' + sanitizeLarkMd(vaultPath) : ''
].filter(Boolean).join('\n\n');

const elements = [
  {
    tag: 'div',
    text: {
      tag: 'lark_md',
      content: mainMarkdown
    }
  }
];

const actions = [];
if (isHttpUrl(canonicalUrl)) {
  actions.push({
    tag: 'button',
    text: {
      tag: 'plain_text',
      content: '\u67e5\u770b\u539f\u6587'
    },
    url: canonicalUrl,
    type: 'primary',
    value: {
      button_id: 'open_source',
      item_id: itemId
    }
  });
}

if (actions.length > 0) {
  elements.push({
    tag: 'action',
    actions
  });
}

return {
  json: {
    ...$json,
    feishu_notify: {
      should_dispatch: shouldDispatch,
      skipped_reason: skippedReason,
      status: shouldDispatch ? 'pending' : 'skipped',
      webhook_configured: webhookConfigured,
      notification_mode: notificationMode,
      message_format: 'interactive_card',
      requested_at: new Date().toISOString(),
      message_preview: truncate(messagePreview, 700),
      request_body: {
        msg_type: 'interactive',
        card: {
          config: {
            wide_screen_mode: true
          },
          header: {
            template: 'blue',
            title: {
              tag: 'plain_text',
              content: 'AI \u4fe1\u606f\u6458\u8981'
            }
          },
          elements
        }
      }
    }
  }
};

const original = $('Build Feishu Message').item.json || {};
const { feishu_notify: originalNotify = {}, ...rest } = original;
const response = $json && typeof $json === 'object' ? $json : {};
const error = typeof response.error === 'string'
  ? response.error.trim()
  : response.error && typeof response.error.message === 'string'
    ? response.error.message.trim()
    : '';
const responseCode = response.StatusCode ?? response.code;
const numericResponseCode = Number(responseCode);
const hasNonZeroResponseCode = responseCode !== undefined && Number.isFinite(numericResponseCode) && numericResponseCode !== 0;
const failed = Boolean(error) || hasNonZeroResponseCode;

return {
  json: {
    ...rest,
    feishu_notify: {
      should_dispatch: Boolean(originalNotify.should_dispatch),
      skipped_reason: '',
      status: failed ? 'failed' : 'sent',
      webhook_configured: Boolean(originalNotify.webhook_configured),
      notification_mode: String(originalNotify.notification_mode || 'silent'),
      message_format: String(originalNotify.message_format || 'interactive_card'),
      requested_at: originalNotify.requested_at || '',
      sent_at: new Date().toISOString(),
      message_preview: String(originalNotify.message_preview || ''),
      error: failed ? (error || 'feishu webhook returned non-zero code ' + responseCode) : '',
      response: failed ? null : response
    }
  }
};

const { feishu_notify: originalNotify = {}, ...rest } = $json || {};
return {
  json: {
    ...rest,
    feishu_notify: {
      should_dispatch: false,
      skipped_reason: String(originalNotify.skipped_reason || 'not_requested'),
      status: 'skipped',
      webhook_configured: Boolean(originalNotify.webhook_configured),
      notification_mode: String(originalNotify.notification_mode || 'silent'),
      message_format: String(originalNotify.message_format || 'interactive_card'),
      requested_at: originalNotify.requested_at || '',
      sent_at: '',
      message_preview: String(originalNotify.message_preview || ''),
      error: '',
      response: null
    }
  }
};

const notify = $json.feishu_notify && typeof $json.feishu_notify === 'object'
  ? $json.feishu_notify
  : {};
return {
  json: {
    ...$json,
    feishu_notify: {
      should_dispatch: Boolean(notify.should_dispatch),
      skipped_reason: String(notify.skipped_reason || ''),
      status: String(notify.status || 'skipped'),
      webhook_configured: Boolean(notify.webhook_configured),
      notification_mode: String(notify.notification_mode || 'silent'),
      message_format: String(notify.message_format || 'interactive_card'),
      requested_at: String(notify.requested_at || ''),
      sent_at: String(notify.sent_at || ''),
      message_preview: String(notify.message_preview || ''),
      error: String(notify.error || ''),
      response: notify.response ?? null
    }
  }
};
